// 1. Lấy dữ liệu từ node trước (AI Router/Classifier)
const d = $input.first().json;
const base = 'https://raw.githubusercontent.com/Meeyana/thacoauto-lib/main/';

// Chuẩn hóa dữ liệu đầu vào
const category = d.category || "";
const brand = (d.brand || "").toLowerCase().trim();
// Giả định AI đã trích xuất được địa điểm hoặc tên showroom (ví dụ: "Phú Mỹ Hưng", "Quận 7")
const location_query = (d.location || "").toLowerCase().trim(); 
const showroom_slug = (d.showroom_slug || "").toLowerCase().trim();

let files = [];
let need_location = false; // Cờ báo hiệu cần hỏi thêm vị trí khách hàng
let bundle = '';

// ==========================================
// 2. LOGIC PHÂN LUỒNG NETWORK_LOCATION
// ==========================================

if (category === "NETWORK_LOCATION") {

    // TH1: Nếu đã xác định được showroom cụ thể (đã có slug)
    if (showroom_slug) {
        // Ví dụ: wiki/dealers/showroom-kia-phu-my-hung.md
        files.push(`wiki/dealers/${showroom_slug}.md`);
    } 

    // TH2: Nếu khách có nhắc đến địa danh nhưng chưa rõ showroom nào (vd: "Showroom ở Bình Dương")
    else if (location_query) {
        // AI có thể tìm file index để lọc hoặc tìm file theo tỉnh thành nếu bạn có cấu trúc đó
        // Ở đây ta ưu tiên lấy index để AI có dữ liệu tổng quát rồi tự lọc
        files.push(`wiki/dealers/index.md`);
        // Có thể bổ sung logic tìm theo tỉnh: files.push(`wiki/dealers/provinces/${location_query}.md`);
    }

    // TH3: Hỏi chung chung hoặc không có thông tin vị trí
    else {
        files.push(`wiki/dealers/index.md`);
        need_location = true; // Bật cờ để AI hỏi "Anh/Chị đang ở khu vực nào?"
    }
}

// ==========================================
// 3. TRUY VẤN DỮ LIỆU TỪ GITHUB
// ==========================================

if (files.length > 0) {
    for (const f of files) {
        try {
            const data = await this.helpers.httpRequest({ 
                method: 'GET', 
                url: base + f, 
                returnFullResponse: false 
            });

            bundle += `\n\n=== TÀI LIỆU HỆ THỐNG MẠNG LƯỚI: ${f} ===\n${typeof data === 'string' ? data : JSON.stringify(data)}`;

        } catch (e) { 
            bundle += `\n\n=== TÀI LIỆU: ${f} ===\n[LỖI: Hiện chưa có dữ liệu chi tiết cho mục này. Vui lòng hướng dẫn khách để lại SĐT để tổng đài viên hỗ trợ trực tiếp.]`; 
        }
    }
}

// ==========================================
// 4. TRẢ KẾT QUẢ
// ==========================================
return [{ 
    json: { 
        ...d,
        need_location: need_location,
        files_used: files, 
        context_bundle: bundle,
        // Gợi ý cho AI cách phản hồi nếu thiếu vị trí
        ai_suggestion: need_location ? "Hãy chào khách và hỏi xem họ đang ở tỉnh thành hoặc quận huyện nào để tìm showroom gần nhất." : "Sử dụng dữ liệu showroom trong context để cung cấp địa chỉ, hotline và giờ làm việc."
    } 
}];
